module RefModule (clk, rst, load, data_in, serial_in, q);
   input clk, rst, load;
   input [2:0] data_in;
   input serial_in;
   output reg [2:0] q;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
      if (rst)
         q <= 3'b000;
      else if (load)
         q <= data_in;
      else
         q <= {serial_in, q[2:1]};
   end
endmodule
